   107→    "iree-llvmcpu-force-arm-streaming",
   108→    llvm::cl::desc(
   109→        "Enables Armv9-A streaming SVE mode for any dispatch region that "
   110→        "contains supported scalable vector operations (i.e., use SSVE rather "
   111→        "than SVE). Requires the +sme feature flag."),
