   118→        createTileAndDistributeToWorkgroupsUsingForallOpPass());
   119→  } else {
   120→    funcPassManager.addPass(createTileAndDistributeToWorkgroupsPass());
   121→    funcPassManager.addPass(createCSEPass());
   122→    funcPassManager.addPass(createConvertToDestinationPassingStylePass());
   123→    funcPassManager.addPass(createFoldAffineMinInDistributedLoopsPass());
   124→  }
   125→  funcPassManager.addPass(createConfigTrackingCanonicalizerPass());
   126→  funcPassManager.addPass(createCSEPass());
   127→  funcPassManager.addPass(createFuseTensorPadWithConsumerPass());
   128→  funcPassManager.addPass(createConcretizePadResultShapePass());
