   135→static bool isValidInterchange(ArrayRef<int64_t> interchange, int numLoops) {
   136→  if (interchange.empty())
   137→    return true;
   138→  llvm::SmallDenseSet<int64_t> s;
   139→  s.insert(interchange.begin(), interchange.end());
   140→  for (int i = 0; i < numLoops; ++i) {
   141→    if (!s.contains(i))
   142→      return false;
   143→  }
   144→  return true;
   145→}
