   147→LogicalResult verifyDoubleTilingExpertPassPipelineConfig(
   148→    Operation *op, TilingConfig &tilingConfig,
   149→    IREE::Codegen::TranslationInfoAttr translationInfo,
   150→    ArrayRef<int64_t> workgroupSize) {
   151→  if (!workgroupSize.empty()) {
   152→    return op->emitOpError(
   153→        "expected workgroup size to be empty for CPU pipelines");
   154→  }
   155→
   156→  // Verify that the translation info is using the right pipeline.
   157→  if (translationInfo.getDispatchLoweringPassPipeline() !=
   158→      IREE::Codegen::DispatchLoweringPassPipeline::CPUDoubleTilingExpert) {
   159→    return op->emitOpError("expected pipeline in translation_info to be ")
   160→           << stringifyEnum(IREE::Codegen::DispatchLoweringPassPipeline::
   161→                                CPUDoubleTilingExpert);
   162→  }
   163→
   164→  if (tilingConfig.getNumTilingLevels() == 6) {
   165→    // TODO: update verification.
   166→    return success();
   167→  }
   168→
   169→  if (tilingConfig.getNumTilingLevels() != 4) {
   170→    return op->emitOpError("expected four tiling levels, got ")
   171→           << tilingConfig.getNumTilingLevels();
   172→  }
   173→
   174→  auto interfaceOp = dyn_cast_or_null<TilingInterface>(op);
   175→  if (interfaceOp) {
   176→    llvm::SmallDenseSet<unsigned> pLoopsSet;
   177→    for (auto [index, iteratorType] :
   178→         llvm::enumerate(interfaceOp.getLoopIteratorTypes())) {
   179→      if (iteratorType == utils::IteratorType::parallel) {
   180→        pLoopsSet.insert(index);
   181→      }
   182→    }
   183→
   184→    SmallVector<int64_t> secondLevelTileSizes;
   185→    std::tie(secondLevelTileSizes, std::ignore) =
   186→        tilingConfig.getVectorCommonParallelSizes();
   187→    for (auto [index, tileSize] : llvm::enumerate(secondLevelTileSizes)) {
   188→      if (tileSize != 0 && !pLoopsSet.contains(index)) {
   189→        return op->emitOpError(
   190→                   "expected only parallel dims to be set in the second tiling "
   191→                   "level, got ")
   192→               << index << "-th tile size set";
   193→      }
   194→    }
   195→
   196→    SmallVector<int64_t> thirdLevelTileSizes;
   197→    std::tie(thirdLevelTileSizes, std::ignore) =
   198→        tilingConfig.getVectorReductionSizes();
   199→    for (auto [index, tileSize] : llvm::enumerate(thirdLevelTileSizes)) {
   200→      if (tileSize != 0 && pLoopsSet.contains(index)) {
   201→        return op->emitOpError(
   202→                   "expected only reduction dims to be set in the third tiling "
   203→                   "level, got ")
   204→               << index << "-th tile size set";
   205→      }
   206→    }
   207→  }
   208→
   209→  // Verify interchange
   210→  auto tileSizesForLevel = tilingConfig.getTileSizes();
   211→  for (int level = 0; level < tilingConfig.getNumTilingLevels(); level++) {
   212→    auto interchange = tilingConfig.getTileInterchangeSizes(level);
   213→    auto &tileSizes = tileSizesForLevel[level];
   214→    if (!isValidInterchange(interchange, tileSizes.size())) {
   215→      return op->emitOpError("expected [0, ")
   216→             << tileSizes.size() << ") to be set exactly once in interchange #"
   217→             << level;
   218→    }
   219→  }
   220→
   221→  // Verify that native vector size is empty.
   222→  SmallVector<int64_t> nativeVectorSize = tilingConfig.getNativeVectorSizes();
   223→  if (!nativeVectorSize.empty()) {
   224→    return op->emitOpError("native_vector_size must be empty");
   225→  }
   226→  return success();
   227→}
