   229→LogicalResult verifyConvTileAndDecomposeExpertConfig(
   230→    Operation *op, TilingConfig &tilingConfig,
   231→    IREE::Codegen::TranslationInfoAttr translationInfo,
   232→    ArrayRef<int64_t> workgroupSize) {
   233→  if (!isa<linalg::ConvolutionOpInterface>(op))
   234→    return success();
   235→
   236→  if (tilingConfig.getNumTilingLevels() == 6) {
   237→    // TODO: update verification.
   238→    return success();
   239→  }
   240→
   241→  if (tilingConfig.getNumTilingLevels() != 4) {
   242→    return op->emitOpError("expected four tiling levels, got ")
   243→           << tilingConfig.getNumTilingLevels();
   244→  }
   245→
   246→  linalg::LinalgOp linalgOp = cast<linalg::LinalgOp>(op);
   247→  SmallVector<int64_t> shape = linalgOp.getStaticLoopRanges();
   248→  for (auto sizes : tilingConfig.getTileSizes()) {
   249→    for (auto [i, size] : llvm::enumerate(sizes)) {
   250→      if (size == 1)
   251→        shape[i] = 1;
   252→      if (shape[i] == -1 || size == 0)
   253→        continue;
   254→      if (shape[i] % size != 0) {
   255→        shape[i] = -1;
   256→      } else {
   257→        shape[i] = size;
   258→      }
   259→    }
   260→  }
   261→
   262→  int64_t khSize, kwSize, ohSize, owSize;
   263→  auto isSizeExtracted =
   264→      TypeSwitch<Operation *, LogicalResult>(op)
   265→          .Case<linalg::Conv2DNhwcHwcfOp, linalg::DepthwiseConv2DNhwcHwcOp,
   266→                linalg::PoolingNhwcSumOp, linalg::PoolingNhwcMaxOp,
   267→                linalg::PoolingNhwcMaxUnsignedOp, linalg::PoolingNhwcMinOp,
   268→                linalg::PoolingNhwcMinUnsignedOp>([&](auto) {
   269→            // Shape: N, OH, OW, OC, KH, KW, (IC)
   270→            khSize = shape[4];
   271→            kwSize = shape[5];
   272→            ohSize = shape[1];
   273→            owSize = shape[2];
   274→            return success();
   275→          })
   276→          .Case<linalg::Conv2DNchwFchwOp>([&](auto) {
   277→            // Shape: N, OC, OH, OW, (IC), KH, KW
   278→            khSize = shape[5];
   279→            kwSize = shape[6];
   280→            ohSize = shape[2];
   281→            owSize = shape[3];
   282→            return success();
   283→          })
   284→          .Case<linalg::PoolingNchwSumOp, linalg::PoolingNchwMaxOp>([&](auto) {
   285→            // Shape: N, OC, OH, OW, KH, KW
   286→            khSize = shape[4];
   287→            kwSize = shape[5];
   288→            ohSize = shape[2];
   289→            owSize = shape[3];
   290→            return success();
   291→          })
   292→          .Default([&](auto) { return failure(); });
   293→  if (failed(isSizeExtracted)) {
   294→    return op->emitOpError("unsupported conv types");
   295→  }
   296→
   297→  bool removeH = (khSize == 1 && ohSize == 1);
   298→  bool removeW = (kwSize == 1 && owSize == 1);
   299→  if (!removeH && !removeW) {
   300→    return op->emitOpError("can't decompose the conv op");
   301→  }
   302→
   303→  return success();
   304→}
