   310→void buildLLVMCPUVectorLoweringPipeline(
   311→    OpPassManager &funcPassManager,
   312→    const LLVMCPUVectorLoweringPassOptions &options) {
   313→  funcPassManager.addPass(createDropVectorUnitDimsPass());
   314→  funcPassManager.addPass(createLLVMCPUVirtualVectorLoweringPass(
   315→      LLVMCPUVirtualVectorLoweringPassOptions{options.splitVectorTransfersTo,
   316→                                              options.enableArmI8mm}));
   317→
   318→  // Make sure we remove redundant vector ops (e.g., vector tranposes) before we
   319→  // lower them and can't be optimized away anymore.
   320→  funcPassManager.addPass(createCanonicalizerPass());
   321→
   322→  LLVMCPUVectorTransferLoweringPassOptions transferLoweringOptions{};
   323→  if (!options.enableArmSME) {
   324→    // The ArmSME dialect has its own (more specific) lowerings for scalable
   325→    // vectors that occur later in the pipeline, so only enable the general
   326→    // lowerings if SME is not available.
   327→    transferLoweringOptions.enableScalableLowerings = true;
   328→  }
   329→  funcPassManager.addPass(
   330→      createLLVMCPUVectorTransferLoweringPass(transferLoweringOptions));
   331→  funcPassManager.addPass(createLLVMCPUVectorTransposeLoweringPass(
   332→      LLVMCPUVectorTransposeLoweringPassOptions{
   333→          options.lowerVectorTransposeToAVX2}));
   334→
   335→  // Potentially removes shape_cast and broadcast on unit dims before shape_cast
   336→  // lowering.
   337→  funcPassManager.addPass(createCanonicalizerPass());
   338→
   339→  // 'vector.shape_cast' are very expensive operations that are even generated
   340→  // by some of the lowerings above (e.g., transpose lowering). There are
   341→  // chances to cancel them out if they are not lowered too early so we lower
   342→  // them at the very end of the pass.
   343→  funcPassManager.addPass(createLLVMCPUVectorShapeCastLoweringPass());
   344→}
