   346→void addCPUBufferOpsTileAndVectorizePipeline(
   347→    OpPassManager &funcPassManager, TilingConfig &tilingConfig,
   348→    LLVMCPUPipelineOptions &pipelineOpt) {
   349→  addTileAndDistributePasses(funcPassManager);
   350→
   351→  // Skip tiling reduction loops because this is expected to apply on copy ops
   352→  // only.
   353→  funcPassManager.addPass(
   354→      createLLVMCPUTilePass(tilingConfig.getVectorCommonParallelLevel()));
   355→  funcPassManager.addPass(createLLVMCPUPeelPass());
   356→  {
   357→    GenericVectorizationPassOptions options;
   358→    options.useConfiguredVectorSizes = pipelineOpt.useConfiguredVectorSizes;
   359→    options.enableVectorMasking = pipelineOpt.enableVectorMasking;
   360→    options.vectorizeGatherAccesses = true;
