   383→void addMultiTilingExpertPassPipeline(OpPassManager &funcPassManager,
   384→                                      TilingConfig &tilingConfig,
   385→                                      LLVMCPUPipelineOptions &pipelineOpt) {
   386→  addTileAndDistributePasses(funcPassManager);
   387→
   388→  SmallVector<int64_t> allFusableLevels(tilingConfig.getFusableLevels());
   389→  // Apply tile and fuse to all the non-distribution fusable levels. Skip
   390→  // distribution level as that level has been fused already.
   391→  if (allFusableLevels.size() > 1) {
   392→    llvm::SmallSetVector<int64_t, 4> fusableLevels(allFusableLevels.begin(),
   393→                                                   allFusableLevels.end());
   394→    for (int i = 0; i < tilingConfig.getNumTilingLevels(); ++i) {
   395→      if (i == tilingConfig.getDistributionLevel())
   396→        continue;
   397→      if (fusableLevels.contains(i)) {
   398→        funcPassManager.addPass(createLLVMCPUTileAndFusePass(i));
   399→        funcPassManager.addPass(createFuseTensorPadWithConsumerPass());
   400→        funcPassManager.addPass(createConcretizePadResultShapePass());
   401→        continue;
   402→      }
   403→
   404→      if (i == tilingConfig.getVectorReductionLevel()) {
   405→        // Run SplitReductionPass before the final reduction Fuse pass, because
   406→        // SplitReductionPass takes care of banked-tiling.
   407→        funcPassManager.addPass(
   408→            createLLVMCPUSplitReductionPass(clEnableReassociateFpReductions));
   409→        funcPassManager.addPass(createLLVMCPUTileRootAndFuseInputOperands(i));
   410→        continue;
   411→      }
   412→
   413→      funcPassManager.addPass(createLLVMCPUTileRootAndFuseInputOperands(i));
   414→    }
   415→  }
   416→
   417→  if (pipelineOpt.enablePeeling) {
   418→    funcPassManager.addPass(createLLVMCPUPeelPass());
   419→  }
   420→
   421→  if (pipelineOpt.enableAArch64SME) {
   422→    funcPassManager.addPass(createLLVMCPU2DScalableTo1DScalablePass());
   423→  }
   424→
   425→  {
   426→    funcPassManager.addPass(createTensorToVectorVectorizePadPass());
