   435→    options.enableVectorMasking = pipelineOpt.enableVectorMasking;
   436→    options.vectorizePadding = true;
   437→    options.vectorizeGatherAccesses = true;
   438→    funcPassManager.addPass(createGenericVectorizationPass(options));
   439→    funcPassManager.addPass(createOptimizeTensorInsertExtractSlicesPass());
   440→    funcPassManager.addPass(createCanonicalizerPass());
   441→    funcPassManager.addPass(createCSEPass());
   442→    if (clFailOnLargeVector) {
